function showPanel(name) {
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.sidebar-link').forEach(l => l.classList.remove('active'));
  const panel = document.getElementById('panel-' + name);
  if (panel) panel.classList.add('active');
  const btn = document.querySelector(`[data-panel="${name}"]`);
  if (btn) btn.classList.add('active');
  document.getElementById('panelTitle').textContent = panelTitles[name] || name;
  // Load data for the panel
  if (loaders[name]) loaders[name]();
}

function showToast(msg) {
  const t = document.createElement('div');
  t.className = 'toast';
  t.textContent = msg;
  document.body.appendChild(t);
  setTimeout(() => t.remove(), 2500);
  document.getElementById('lastSaved').textContent = new Date().toLocaleTimeString('ar-SA');
}

function closeModal() { document.getElementById('modal').style.display = 'none'; }

function handleImageUpload(inputEl, targetInputId, previewImgId) {
  const file = inputEl.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(e) {
    document.getElementById(targetInputId).value = e.target.result;
    if (previewImgId) {
      const p = document.getElementById(previewImgId);
      if (p) {
        p.src = e.target.result;
        p.style.display = 'block';
      }
    }
  };
  reader.readAsDataURL(file);
}
function openModal(title, html) {
  document.getElementById('modal-title').textContent = title;
  document.getElementById('modal-body').innerHTML = html;
  document.getElementById('modal').style.display = 'flex';
}

