function loadSettings() {
  const s = SiteData.getData('settings');
  Object.keys(s).forEach(k => {
    const el = document.getElementById('s-' + k);
    if (el) el.value = s[k] || '';
  });
  renderSettingsList('phones', s.phones || []);
  renderSettingsList('emails', s.emails || []);
  renderSettingsList('addresses', s.addresses || []);
}
function saveSettings() {
  const s = SiteData.getData('settings');
  Object.keys(s).forEach(k => {
    const el = document.getElementById('s-' + k);
    if (el) s[k] = el.value;
  });
  s.phones = Array.from(document.querySelectorAll('.s-phones-item')).map(el => el.value).filter(val => val.trim() !== '');
  s.emails = Array.from(document.querySelectorAll('.s-emails-item')).map(el => el.value).filter(val => val.trim() !== '');
  s.addresses = Array.from(document.querySelectorAll('.s-addresses-item')).map(el => el.value).filter(val => val.trim() !== '');

  if (s.phones.length > 0) s.phone = s.phones[0];
  if (s.emails.length > 0) s.email = s.emails[0];
  if (s.addresses.length > 0) s.address = s.addresses[0];

  SiteData.saveData('settings', s);
  showToast('تم حفظ الإعدادات بنجاح ✓');
  loadSettings();
}

